# ── DB setup ──────────────────────────────────────────────────────────────────
DATABASE_URL = os.getenv("DATABASE_URL", "sqlite+aiosqlite:///./finwatch.db")
engine = create_async_engine(DATABASE_URL, echo=False)
AsyncSessionLocal = sessionmaker(engine, class_=AsyncSession, expire_on_commit=False)
Base = declarative_base()

class Official(Base):
    __tablename__ = "officials"
    id = Column(Integer, primary_key=True)
    name = Column(String, nullable=False, index=True)
    initials = Column(String); role = Column(String); state = Column(String, index=True)
    ministry = Column(String); party = Column(String)
    declared_assets_cr = Column(Float, default=0); unexplained_wealth_cr = Column(Float, default=0)
    risk_score = Column(Integer, default=0); risk_level = Column(String, default="Low")
    pan_partial = Column(String); ec_affidavit_url = Column(String)
    myneta_id = Column(String); source = Column(String)
    last_synced = Column(DateTime, default=datetime.utcnow)
    companies = relationship("Company", back_populates="official", cascade="all, delete-orphan")
    asset_history = relationship("AssetHistory", back_populates="official", cascade="all, delete-orphan")
    properties = relationship("Property", back_populates="official", cascade="all, delete-orphan")
    events = relationship("FlaggedEvent", back_populates="official", cascade="all, delete-orphan")

class Company(Base):
    __tablename__ = "companies"
    id = Column(Integer, primary_key=True)
    official_id = Column(Integer, ForeignKey("officials.id"))
    name = Column(String); cin = Column(String); link_type = Column(String)
    turnover_cr = Column(Float, default=0); gst_filed = Column(Boolean, default=False); it_filed = Column(Boolean, default=False)
    official = relationship("Official", back_populates="companies")

class AssetHistory(Base):
    __tablename__ = "asset_history"
    id = Column(Integer, primary_key=True)
    official_id = Column(Integer, ForeignKey("officials.id"))
    year = Column(Integer); declared_cr = Column(Float); estimated_cr = Column(Float)
    official = relationship("Official", back_populates="asset_history")

class Property(Base):
    __tablename__ = "properties"
    id = Column(Integer, primary_key=True)
    official_id = Column(Integer, ForeignKey("officials.id"))
    description = Column(String); registrant = Column(String); value_cr = Column(Float)
    date = Column(String); flag = Column(String)
    official = relationship("Official", back_populates="properties")

class FlaggedEvent(Base):
    __tablename__ = "flagged_events"
    id = Column(Integer, primary_key=True)
    official_id = Column(Integer, ForeignKey("officials.id"))
    date = Column(String); event = Column(Text); severity = Column(String); source = Column(String)
    official = relationship("Official", back_populates="events")

async def get_db():
    async with AsyncSessionLocal() as session:
        yield session

logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)
ANTHROPIC_API_KEY = os.getenv("ANTHROPIC_API_KEY", "")

